import React, { useEffect, useState } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const clientId = 'your_client_id';
  const clientSecret = 'your_client_secret';
  const redirectUri = 'your_redirect_uri';

  useEffect(() => {
    // Simulate initial token fetch
    fetchTokens();
  }, []);

  const fetchTokens = async () => {
    try {
      const response = await axios.post('https://oauth2-server.com/token', null, {
        params: {
          grant_type: 'authorization_code',
          code: 'your_authorization_code',
          redirect_uri,
        },
        auth: {
          username: clientId,
          password: clientSecret,
        },
      });
      setAccessToken(response.data.access_token);
      setRefreshToken(response.data.refresh_token);
    } catch (error) {
      console.error('Error fetching tokens:', error);
    }
  };

  const refreshTokens = async () => {
    try {
      const response = await axios.post('https://oauth2-server.com/token', null, {
        params: {
          grant_type: 'refresh_token',
          refresh_token: refreshToken,
        },
        auth: {
          username: clientId,
          password: clientSecret,
        },
      });
      setAccessToken(response.data.access_token);
    } catch (error) {
      console.error('Error refreshing tokens:', error);
    }
  };

  const handleLogin = async () => {
    // Simulate login process
    await fetchTokens();
  };

  return (
    <View>
      <Text>{accessToken ? `Logged in with token: ${accessToken}` : 'Not logged in'}</Text>
      <Button title="Login" onPress={handleLogin} />
      {accessToken && <Button title="Refresh Token" onPress={refreshTokens} />}
    </View>
  );
};

export default App;